from typing import List

class Solution:
    def minimumAddedCoins(self, coins: List[int], target: int) -> int:
        coins.sort()
        added = 0
        reach = 0  # we can form all sums in [1..reach]

        for c in coins:
            if c > target:
                break
            if c > reach + 1:
                # need to cover reach+1 using added coins (greedily doubling)
                while reach < target and reach + 1 < c:
                    need = reach + 1
                    added += 1
                    # adding coin of value need extends coverage to 2*reach + 1
                    reach = 2 * reach + 1
                    if reach >= target:
                        return added
            # now c <= reach + 1, so it can be used to extend coverage
            if c <= reach + 1:
                reach += c
                if reach >= target:
                    return added

        # after processing all coins, extend to target if needed
        while reach < target:
            added += 1
            reach = 2 * reach + 1
        return added
