from typing import List

class Solution:
    def minimumAddedCoins(self, coins: List[int], target: int) -> int:
        coins.sort()
        added = 0
        # max_reachable = largest value in [1..target] that we can form using current coins
        max_reachable = 0

        for c in coins:
            if c > max_reachable + 1:
                # Need to add coins to extend coverage up to at least c-1, in powers of two greedy,
                # but we can do it by repeatedly adding coin (max_reachable+1) until coverage reaches c-1.
                need = max_reachable + 1
                while need < c and need <= target:
                    added += 1
                    max_reachable += need
                    need = max_reachable + 1
                if max_reachable >= target:
                    return added

            if c <= max_reachable + 1:
                max_reachable += c
                if max_reachable >= target:
                    return added

        # After using all coins, extend coverage to target
        while max_reachable < target:
            need = max_reachable + 1
            added += 1
            max_reachable += need

        return added
