from typing import List

class Solution:
    def minimumAddedCoins(self, coins: List[int], target: int) -> int:
        coins.sort()
        added = 0
        # reachable: all sums in [1, reachable] are obtainable with current coins
        reachable = 0

        for c in coins:
            if c > reachable + 1:
                # Need to add coin of value reachable+1, then reachable doubles +1
                # Greedy: always extend coverage with coin = reachable+1
                while c > reachable + 1 and reachable < target:
                    next_coin = reachable + 1
                    reachable += next_coin
                    added += 1
                if c <= reachable + 1:
                    reachable += c
            else:
                reachable += c

            if reachable >= target:
                return added

        # After all existing coins, keep adding until we cover [1, target]
        while reachable < target:
            next_coin = reachable + 1
            reachable += next_coin
            added += 1

        return added
